int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int copiedArr[n];
    for (int i = 0; i < n; i++) {
        copiedArr[i] = arr[i];
    }
    for (int i = 0; i < n; i++) {
        printf("%d ", copiedArr[i]);
    }
    return 0;
}

