code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = scanner.nextInt();
        }
        int[] copiedArr = new int[n];
        for (int i = 0; i < n; i++) {
            copiedArr[i] = arr[i];
        }
        for (int i = 0; i < n; i++) {
            System.out.print(copiedArr[i] + " ");
        }
    }
}

